		return 0
	}

	return pers[0]
}

func memPercent() float64 {
	v, err := mem.VirtualMemory()
	if err != nil {
		logs.Errorf("failed to get mem, err:%v", err)
		return 0
	}
	return v.UsedPercent
}

func (l *Limiter) Limit(fn func()) {
	for {
		mem := atomich.LoadFloat64(&l.memu)
		if l.MemUsage > 0 && mem > 0 && l.MemUsage < mem {
			time.Sleep(100 * time.Millisecond)
			continue
		}
		cpu := atomich.LoadFloat64(&l.cpuu)
		if l.CpuUsage > 0 && cpu > 0 && l.CpuUsage < cpu {
